2706 PreservedAnalyses VectorCombinePass::run(Function &F,
2707                                          FunctionAnalysisManager &FAM) {
2708   auto &AC = FAM.getResult<AssumptionAnalysis>(F);
2709   TargetTransformInfo &TTI = FAM.getResult<TargetIRAnalysis>(F);
2710   DominatorTree &DT = FAM.getResult<DominatorTreeAnalysis>(F);
2711   AAResults &AA = FAM.getResult<AAManager>(F);
2712   const DataLayout *DL = &F.getDataLayout();
2713   VectorCombine Combiner(F, TTI, DT, AA, AC, DL, TryEarlyFoldsOnly);
2714   if (!Combiner.run())
2715     return PreservedAnalyses::all();
2716   PreservedAnalyses PA;
2717   PA.preserveSet<CFGAnalyses>();
2718   return PA;
2719 }
